		"      ....... ######################.... ############     ",
		".    .  .... ########################... ###########      ",
		"   ..   ....#########################.. .###########      ",
		"    .       #########################.   .##########      ",
		"   ....     .########################.      ########      ",
		"  .....      .  ####################.        #######.     ",
		"......     .. . ################## . .      .#######      ",
		"......       #####################  .      .#######       ",
		"......   .###########################  ..  #######        ",
		"...    . ########################################.        ",
		"       ####################################### .          ",
		"      ##################################    .             ",
