	for i < len(os.Args) {
		arg := os.Args[i]
		switch {
		case arg == "-h" || arg == "--help":
			printHelp()
			os.Exit(0)
		case arg == "-V" || arg == "--version":
			fmt.Println("pingu: v-rev9c2e3df")
			os.Exit(0)
		case arg == "-P" || arg == "--privilege":
			privilege = true
			i++
		case arg == "-c" || strings.HasPrefix(arg, "-c="):
			i++
			if i >= len(os.Args) {
				fmt.Fprintf(os.Stderr, "[ ERROR ] unexpected end of options\n")
				os.Exit(1)
			}
			if strings.HasPrefix(arg, "-c=") {
				v, err := strconv.Atoi(strings.TrimPrefix(arg, "-c="))
				if err != nil {
					fmt.Fprintf(os.Stderr, "[ ERROR ] invalid count: %s\n", arg[3:])
					os.Exit(1)
				}
				count = v
				i--
			} else {
				v, err := strconv.Atoi(os.Args[i])
				if err != nil {
					fmt.Fprintf(os.Stderr, "[ ERROR ] invalid count: %s\n", os.Args[i])
					os.Exit(1)
				}
				count = v
			}
		case arg == "--count" || strings.HasPrefix(arg, "--count="):
			i++
			if strings.HasPrefix(arg, "--count=") {
				v, err := strconv.Atoi(strings.TrimPrefix(arg, "--count="))
				if err != nil {
					fmt.Fprintf(os.Stderr, "[ ERROR ] invalid count: %s\n", arg[8:])
					os.Exit(1)
				}
				count = v
				i--
			} else {
				if i >= len(os.Args) {
					fmt.Fprintf(os.Stderr, "[ ERROR ] missing count value\n")
					os.Exit(1)
