				if err != nil {
					fmt.Fprintf(os.Stderr, "[ ERROR ] invalid count: %s\n", os.Args[i])
					os.Exit(1)
				}
				count = v
			}
		default:
			host = arg
			i++
		}
	}

	if host == "" {
		fmt.Fprintln(os.Stderr, "[ ERROR ] must requires an argument")
		os.Exit(1)
	}

	runPing(host, count, privilege)
}

func printHelp() {
	fmt.Println("Usage:")
	fmt.Println("  pingu [OPTIONS] HOST")
	fmt.Println()
	fmt.Println("`ping` command but with pingu")
	fmt.Println()
	fmt.Println("Application Options:")
	fmt.Println("  -c, --count=     Stop after <count> replies (default: 20)")
	fmt.Println("  -P, --privilege  Enable privileged mode")
	fmt.Println("  -V, --version    Show version")
	fmt.Println()
	fmt.Println("Help Options:")
	fmt.Println("  -h, --help       Show this help message")
}

// Raw ping using Unix domain - actually use a raw socket approach or go-ping library concept
// For now, let's try to use syscall

type icmpPool struct {
	mu     sync.Mutex
	frames []int // frame indices per seq
}

func runPing(host string, count int, privilege bool) {
	ctx, cancel := context.WithCancel(context.Background())
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
	go func() {
		<-sigCh
		cancel()
	}()

	res := pingHost(ctx, host, count, privilege)

	fmt.Fprint(os.Stderr, "\n") // newline after last penguin line

	// Print statistics
	printStats(res, host, count)
}

type pingResult struct {
	addr  string
	ttl   int
	rtt   time.Duration
	seq   int
	bytes int
	err   error
}

func pingHost(ctx context.Context, host string, count int, privileged bool) []*pingResult {
	// Use Go's ping via raw socket
	// For simplicity, use gorilla/ping concept - but we can't use external deps
	// Let's use a raw ping approach

	pinger, err := newPinger(ctx, host, privileged)
	if err != nil {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: %v\n", err)
		return nil
	}

	var results []*pingResult
	var mutex sync.Mutex
	var wg sync.WaitGroup
	frameIdx := 0
	frameMutex := sync.Mutex{}

	// Start receiving
	recvCh := make(chan *pingResult, count)
	go recvLoop(ctx, pinger, count, recvCh)

	// Resolve address info for header
	addrStr := pinger.addr.String()

	// Print header
	fmt.Printf("PING %s (%s) type `Ctrl-C` to abort\n", host, addrStr)

	for seq := 0; seq < count; seq++ {
		done := make(chan struct{})
		wg.Add(1)
		seq := seq
		go func() {
			defer wg.Done()
			pinger.sendPacket(seq)
			close(done)
		}()
		<-done
	}
	pinger.close()

	// Collect results with penguin display
	timeoutCh := time.After(10 * time.Second)
	resultsCollected := 0
	seen := make(map[int]bool)

	for resultsCollected < count {
		select {
		case <-ctx.Done():
			goto done
		case r := <-recvCh:
			if r == nil {
				continue
			}
			mutex.Lock()
			if seen[r.seq] {
				mutex.Unlock()
				continue
			}
			seen[r.seq] = true
			results = append(results, r)
			frameMutex.Lock()
			frameIdx++
			frame := frameIdx - 1
			if frame >= 20 {
				frame = frame % 20
			}
			frameStr := penguinArt[frame % 20]
			frameMutex.Unlock()
			mutex.Unlock()
			fmt.Printf("%s seq=%d 32bytes from %s: ttl=%d time=%sµs\n",
				frameStr, r.seq, r.addr, r.ttl, formatDuration(r.rtt))
			resultsCollected++
		case <-timeoutCh:
			goto done
		}
	}
done:
	wg.Wait()
	return results
}

func formatDuration(d time.Duration) string {
	micros := float64(d) / float64(time.Microsecond)
	return strconv.FormatFloat(micros, 'f', -1, 64)
}

type pinger struct {
	conn net.PacketConn
	addr *net.UDPAddr
	ctx  context.Context
	id   int
	seq  int
}

type icmpHeader struct {
	Type     uint8
	Code     uint8
	Checksum uint16
	ID       uint16
	Seq      uint16
