		return nil, fmt.Errorf("failed to init pinger lookup %s: %w", host, err)
	}
	if len(ipAddresses) == 0 {
		return nil, fmt.Errorf("failed to resolve %s", host)
	}
	targetIP := ipAddresses[0].IP

	port := 0 // ICMP uses port 0 effectively
	// On Linux, use raw socket
	addr := &net.UDPAddr{IP: targetIP, Port: port}

	conn, err := net.ListenPacket("ip4:icmp", "0.0.0.0")
	if err != nil {
		return nil, fmt.Errorf("failed to create socket: %w", err)
	}

