	buf[1] = hdr.Code
	buf[2] = byte(hdr.ID >> 8)
	buf[3] = byte(hdr.ID)
	buf[4] = byte(hdr.Seq >> 8)
	buf[5] = byte(hdr.Seq)
	// Timestamp
	ts := time.Now().UnixNano()
	binary.BigEndian.PutUint64(buf[8:16], uint64(ts))
