	buf[2] = 0
	buf[3] = 0
	buf[4] = 0
	buf[5] = 0
	csum := checksum(buf[:8])
	binary.BigEndian.PutUint16(buf[0:2], csum)

	p.conn.WriteTo(buf, p.addr)
}

