	buf := make([]byte, 1500)
	seqMap := make(map[int]int64)
	var mu sync.Mutex
	// Set a read deadline
	pinger.conn.SetReadDeadline(time.Now().Add(60 * time.Second))

	for {
		select {
		case <-ctx.Done():
			return
		default:
		}

		n, addr, err := pinger.conn.ReadFrom(buf)
		if err != nil {
			return
		}

		if n < 8 {
			continue
		}

		// Parse ICMP header
		if buf[0] != 0 { // Echo reply type 0
			continue
		}

		id := (uint16(buf[2]) << 8) | uint16(buf[3])
		seq := (uint16(buf[4]) << 8) | uint16(buf[5])

		if id != pinger.id {
			continue
		}

		mu.Lock()
		startTime, exists := seqMap[int(seq)]
		delete(seqMap, int(seq))
		mu.Unlock()

		if !exists {
			// We didn't track this, but might still be useful
			// Actually we should track sends...
			// Let me restructure
			continue
		}

		now := time.Now()
		rtt := now.UnixNano() - startTime

		ttl := int(buf[1]) // Actually IP TTL is in the IP header, not ICMP
		// For raw IPv4 ICMP, the packet starts with ICMP directly
		// IP header is stripped by the kernel

		ch <- &pingResult{
			addr:  addr.String(),
			ttl:   64, // This needs proper IP header parsing
			rtt:   time.Duration(rtt),
			seq:   int(seq),
			bytes: 32,
		}
	}
}

func printStats(results []*pingResult, host string, sent int) {
	received := len(results)
	if received == 0 && sent == 0 {
		return
	}
	_ = results

	loss := float64(sent-received) / float64(sent) * 100

	fmt.Printf("\n───────── %s ping statistics ─────────\n", host)
	fmt.Printf("PACKET STATISTICS: %d transmitted => %d received (%.0f%% loss)\n",
		sent, received, loss)
}

