		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: failed to init pinger lookup %s: %v\n", host, err)
		return
	}
	if len(ipAddrs) == 0 {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: failed to resolve %s\n", host)
		return
	}
	targetIP := ipAddrs[0].IP

	// Open ICMP socket
	conn, err := net.ListenPacket("ip4:icmp", "0.0.0.0")
	if err != nil {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: %v\n", err)
		return
	}
	defer conn.Close()

	dstAddr := net.IPAddr{IP: targetIP, Zone: ""}

	myID := uint16(os.Getpid())&0xFF << 8 | uint16(os.Getpid())&0xFF
	// Better: use random
	rand.Seed(time.Now().UnixNano())
	myID = uint16(rand.Int())

	// Track sent packets
	sentMux := sync.Mutex{}
	sent := make(map[int]time.Time)

	// Track received packets  
	var resultMux sync.Mutex
	results := make([]*pingResult, 0, count)
	receivedCount := 0
	nextFrame := 0

	// Result channel
	doneCh := make(chan *pingResult, count)

	// Start receiver
	go func() {
		buf := make([]byte, 1500)
		for {
			select {
			case <-ctx.Done():
				return
			default:
			}
			conn.SetReadDeadline(time.Now().Add(5 * time.Second))
			n, addr, err := conn.ReadFrom(buf)
			if err != nil {
				if netErr, ok := err.(net.Error); ok && netErr.Timeout() {
					continue
				}
				return
			}
			if n < 8 {
				continue
			}
			// ICMP reply: type=0, code=0
			if buf[0] != 0 {
				continue
			}
			respID := uint16(buf[2])<<8 | uint16(buf[3])
			respSeq := uint16(buf[4])<<8 | uint16(buf[5])
			if respID != myID {
				continue
			}
			seq := int(respSeq)
			sentMux.Lock()
			ts, ok := sent[seq]
			delete(sent, seq)
			sentMux.Unlock()
			if !ok {
				continue
			}
			rtt := time.Since(ts)

			// Extract TTL from IP header - with ip4:icmp, IP header is stripped
			// but we might still get it. Let's try.
			ttl := 64 // default
			// Actually with "ip4:icmp" protocol, IP header is stripped.
			// With "ip:1" it's included. Let's use "ip:1" instead.

			doneCh <- &pingResult{
				addr:  addr.String(),
				ttl:   ttl,
				rtt:   rtt,
				seq:   seq,
				bytes: 32,
			}
		}
	}()

	// Send packets and print header
	fmt.Printf("PING %s (%s) type `Ctrl-C` to abort\n", host, targetIP.String())

	for seq := 0; seq < count; seq++ {
		// Build ICMP packet
		pkt := &icmpPacket{
			Type: 8,
			Code: 0,
			ID:   myID,
			Seq:  uint16(seq),
		}
		binary.BigEndian.PutUint64(pkt.Timestamp[:], uint64(time.Now().UnixNano()))
		copy(pkt.Payload[:], make([]byte, 56))

		data := make([]byte, 64)
		bin := &bytes.Buffer{}
		bin.WriteByte(pkt.Type)
		bin.WriteByte(pkt.Code)
		binary.Write(bin, binary.BigEndian, uint16(0)) // placeholder for checksum
		binary.Write(bin, binary.BigEndian, pkt.ID)
		binary.Write(bin, binary.BigEndian, pkt.Seq)
		bin.Write(pkt.Timestamp[:])
		bin.Write(pkt.Payload[:])
		data = bin.Bytes()

		// Compute checksum
		var sum uint32
		for i := 0; i < len(data)-1; i += 2 {
			sum += uint32(data[i])<<8 | uint32(data[i+1])
		}
		if len(data)%2 == 1 {
			sum += uint32(data[len(data)-1]) << 8
		}
		for sum > 0xFFFF {
			sum = (sum >> 16) + (sum & 0xFFFF)
		}
		csum := uint16(^sum)
		binary.BigEndian.PutUint16(data[2:4], csum)

		sendTime := time.Now()
		conn.WriteTo(data, &dstAddr)

		sentMux.Lock()
		sent[seq] = sendTime
		sentMux.Unlock()

		// Wait for this packet's response (or timeout)
		// Actually, better to wait for any response
		// Let's use a non-blocking approach
		// Wait a bit for throughput
		time.Sleep(100 * time.Millisecond)
	}

	// Wait for all responses
	timeout := time.After(30 * time.Second)
	for receivedCount < count {
		select {
		case r := <-doneCh:
			resultMux.Lock()
			results = append(results, r)
			receivedCount++
			resultMux.Unlock()

			frame := penguinFrames[nextFrame%len(penguinFrames)]
			nextFrame++

			fmt.Printf("%s seq=%d 32bytes from %s: ttl=%d time=%dµs\n",
				frame, r.seq, r.addr, r.ttl, int64(r.rtt)/1000)
		case <-timeout:
			goto printStats
		case <-ctx.Done():
			goto printStats
		}
	}

printStats:
	cancel()

	// Print statistics
	fmt.Printf("\n───────── %s ping statistics ─────────\n", host)

	sentTotal := count
	recvTotal := receivedCount
	lossPct := float64(0)
	if sentTotal > 0 {
		lossPct = float64(sentTotal-recvTotal) / float64(sentTotal) * 100
	}
	fmt.Printf("PACKET STATISTICS: %d transmitted => %d received (%.0f%% loss)\n",
		sentTotal, recvTotal, lossPct)

	if len(results) > 0 {
		minRtt := results[0].rtt
		maxRtt := results[0].rtt
		totalRtt := int64(0)
		for _, r := range results {
			totalRtt += int64(r.rtt)
			if r.rtt < minRtt {
				minRtt = r.rtt
			}
			if r.rtt > maxRtt {
				maxRtt = r.rtt
			}
		}
		avgRtt := time.Duration(totalRtt / int64(len(results)))

		// Calculate stddev
		variance := float64(0)
		for _, r := range results {
			diff := float64(r.rtt - avgRtt)
			variance += diff * diff
		}
		variance /= float64(len(results))
		stddev := time.Duration(math.Sqrt(variance))

		fmt.Printf("ROUND TRIP: min=%dµs avg=%dµs max=%dµs stddev=%dµs\n",
			int64(minRtt)/1000, int64(avgRtt)/1000, int64(maxRtt)/1000, int64(stddev)/1000)
	}
}
GOEOF"}

