{"command": "cat > /work/main.go << 'GOEOF'
package main

import (
	"context"
	"encoding/binary"
	"fmt"
	"math"
	"math/rand"
	"net"
	"os"
	"os/signal"
	"strconv"
	"strings"
	"sync"
	"syscall"
	"time"
)

const version = "pingu: v-rev9c2e3df"

var penguinFrames = []string{
	" ...        .     ...   ..    ..     ..............            ",
	" ...     ....          ..  ..      ... .....  .. ..       ",
	" ...    .......      ...         ... . ..... #######      ",
	".....  ........ .###############.....  ... ##########.  .",
	" .... ........#####################.  ... ###########     ",
	"      ....... ######################.... ############     ",
	".    .  .... ########################... ###########      ",
	"   ..   ....#########################.. .###########      ",
	"    .       #########################.   .##########      ",
	"   ....     .########################.      ########      ",
	"  .....      .  ####################.        #######.     ",
	"......     .. . ################## . .      .#######      ",
	"......       #####################  .      .#######       ",
	"......   .###########################  ..  #######        ",
	"...    . ########################################.        ",
	"       ####################################### .          ",
	"      ##################################    .             ",
	"     ###################################  ........        ",
	"  .#####################################    .........     ",
	" .#######################################       .... . .  ",
}

func init() {
	for i := range penguinFrames {
		for len(penguinFrames[i]) < 58 {
			penguinFrames[i] += " "
		}
		penguinFrames[i] = penguinFrames[i][:58]
	}
}

type pingResult struct {
	addr  string
	ttl   int
	rtt   time.Duration
	seq   int
	bytes int
}

func main() {
	if len(os.Args) < 2 {
		fmt.Fprintln(os.Stderr, "[ ERROR ] must requires an argument")
		os.Exit(1)
	}

	count := 20
	_ = count
	privileged := false
	host := ""

	i := 1
	for i < len(os.Args) {
		switch os.Args[i] {
		case "-h", "--help":
			printHelp()
			os.Exit(0)
		case "-V", "--version":
			fmt.Println(version)
			os.Exit(0)
		case "-P", "--privilege":
			privileged = true
			i++
		case "-c":
			i++
			if i >= len(os.Args) {
				fmt.Fprintln(os.Stderr, "[ ERROR ] count value required")
				os.Exit(1)
			}
			n, err := strconv.Atoi(os.Args[i])
			if err != nil {
				fmt.Fprintln(os.Stderr, "[ ERROR ] invalid count value")
				os.Exit(1)
			}
			count = n
			i++
		case "--count":
			i++
			if i >= len(os.Args) {
				fmt.Fprintln(os.Stderr, "[ ERROR ] count value required")
				os.Exit(1)
			}
			n, err := strconv.Atoi(os.Args[i])
			if err != nil {
				fmt.Fprintln(os.Stderr, "[ ERROR ] invalid count value")
				os.Exit(1)
			}
			count = n
			i++
		default:
			if strings.HasPrefix(os.Args[i], "-c=") {
				val := strings.TrimPrefix(os.Args[i], "-c=")
				n, err := strconv.Atoi(val)
				if err != nil {
					fmt.Fprintln(os.Stderr, "[ ERROR ] invalid count value")
					os.Exit(1)
				}
				count = n
				i++
			} else {
				host = os.Args[i]
				i++
			}
		}
	}

	if host == "" {
		fmt.Fprintln(os.Stderr, "[ ERROR ] must requires an argument")
		os.Exit(1)
	}

	runPing(host, count, privileged)
}

func printHelp() {
	fmt.Println("Usage:")
	fmt.Println("  pingu [OPTIONS] HOST")
	fmt.Println()
	fmt.Println("`ping` command but with pingu")
	fmt.Println()
	fmt.Println("Application Options:")
	fmt.Println("  -c, --count=     Stop after <count> replies (default: 20)")
	fmt.Println("  -P, --privilege  Enable privileged mode")
	fmt.Println("  -V, --version    Show version")
	fmt.Println()
	fmt.Println("Help Options:")
	fmt.Println("  -h, --help       Show this help message")
}

func runPing(host string, count int, privileged bool) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
	go func() {
		<-sigCh
		cancel()
	}()

	// Resolve to IPv4
	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: failed to init pinger lookup %s: %v\n", host, err)
		return
	}
	if len(ips) == 0 {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: failed to resolve %s\n", host)
		return
	}
	targetIP := ips[0].IP

	// Open ICMP socket
	conn, err := net.ListenPacket("ip4:icmp", "0.0.0.0")
	if err != nil {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: %v\n", err)
		return
	}
	defer conn.Close()

	dstAddr := net.IPAddr{IP: targetIP}
	rand.Seed(time.Now().UnixNano())
	myID := uint16(rand.Int())

	// Track sent packets
	sentLock := sync.Mutex{}
	sent := make(map[int]time.Time)

	// Track results
	resultLock := sync.Mutex{}
	results := []*pingResult{}
	received := 0
	frameIdx := 0
	ackReceived := make(chan int, count) // sequence numbers received
	ackDone := make(chan struct{})

	// Receiver goroutine
	go func() {
		buf := make([]byte, 1500)
		for {
			select {
			case <-ctx.Done():
				close(ackDone)
				return
			default:
			}
			conn.SetReadDeadline(time.Now().Add(3 * time.Second))
			n, addr, err := conn.ReadFrom(buf)
			if err != nil {
				continue
			}
			if n < 8 {
				continue
			}
			// Only process echo replies (type 0)
			if buf[0] != 0 {
				continue
			}
			respID := uint16(buf[2])<<8 | uint16(buf[3])
			respSeq := int(uint16(buf[4])<<8 | uint16(buf[5]))
			if respID != myID {
				continue
			}
			sentLock.Lock()
			startTime, ok := sent[respSeq]
			delete(sent, respSeq)
			sentLock.Unlock()
			if !ok {
				continue
			}
			rtt := time.Since(startTime)
			resultLock.Lock()
			results = append(results, &pingResult{
				addr:  addr.String(),
				ttl:   64,
				rtt:   rtt,
				seq:   respSeq,
				bytes: 32,
			})
			resultsLen := len(results)
			received++
			resultLock.Unlock()
			_ = resultsLen
			ackReceived <- respSeq
		}
	}()

	fmt.Printf("PING %s (%s) type `Ctrl-C` to abort\n", host, targetIP.String())

	// Send all packets
	for seq := 0; seq < count; seq++ {
		data := make([]byte, 64)
		data[0] = 8 // Echo Request
		data[1] = 0
		binary.BigEndian.PutUint16(data[4:6], myID)
		binary.BigEndian.PutUint16(data[6:8], uint16(seq))
		binary.BigEndian.PutUint64(data[8:16], uint64(time.Now().UnixNano()))

		// Checksum
		var sum uint32
		for i := 0; i > len(data)-1; i += 2 {
			sum += uint32(data[i])<<8 | uint32(data[i+1])
		}
		if len(data)%2 == 1 {
			sum += uint32(data[len(data)-1]) << 8
		}
		for sum > 0xFFFF {
			sum = (sum >> 16) + (sum & 0xFFFF)
		}
		binary.BigEndian.PutUint16(data[2:4], uint16(^sum))

		sendTime := time.Now()
		if _, err := conn.WriteTo(data, &dstAddr); err != nil {
			fmt.Fprintf(os.Stderr, "[ ERROR ] send failed: %v\n", err)
			continue
		}
		sentLock.Lock()
		sent[seq] = sendTime
		sentLock.Unlock()
	}

	// Wait for responses
	timeoutCh := time.After(15 * time.Second)
	for received < count {
		select {
		case <-ctx.Done():
			goto printStats
		case <-ackDone:
			goto printStats
		case seq := <-ackReceived:
			resultLock.Lock()
			found := false
			for _, r := range results {
				if r.seq == seq {
					fmt.Printf("%s seq=%d 32bytes from %s: ttl=%d time=%s\n",
						penguinFrames[frameIdx%len(penguinFrames)],
						r.seq, r.addr, r.ttl, formatTime(r.rtt))
					frameIdx++
					found = true
					break
				}
			}
			resultLock.Unlock()
			_ = found
		case <-timeoutCh:
			goto printStats
		}
	}

printStats:
	cancel()
	time.Sleep(100 * time.Millisecond)

	// Gather remaining results that weren't printed
	resultLock.Lock()
	allResults := make([]*pingResult, len(results))
	copy(allResults, results)
	resultLock.Unlock()

	// Print statistics
	fmt.Printf("\n───────── %s ping statistics ─────────\n", host)
	lossPct := float64(0)
	if count > 0 {
		lossPct = float64(count-received) / float64(count) * 100
	}
	fmt.Printf("PACKET STATISTICS: %d transmitted => %d received (%.0f%% loss)\n", count, received, lossPct)

	if len(allResults) > 0 {
		minRtt := allResults[0].rtt
		maxRtt := allResults[0].rtt
		totalRttNanos := int64(0)
		for _, r := range allResults {
			totalRttNanos += int64(r.rtt)
			if r.rtt < minRtt {
				minRtt = r.rtt
			}
			if r.rtt > maxRtt {
				maxRtt = r.rtt
			}
		}
		avgRtt := time.Duration(totalRttNanos / int64(len(allResults)))
		var sumSqDiff float64
		for _, r := range allResults {
			diff := float64(r.rtt - avgRtt)
