			sumSqDiff += diff * diff
		}
		stddev := time.Duration(math.Sqrt(sumSqDiff / float64(len(allResults))))

		fmt.Printf("ROUND TRIP: min=%s avg=%s max=%s stddev=%s\n",
			formatTime(minRtt), formatTime(avgRtt), formatTime(maxRtt), formatTimeStd(stddev))
	}
}

func formatTime(d time.Duration) string {
	micros := d.Microseconds()
	if micros == 0 {
		return fmt.Sprintf("%.0fµs", float64(d)/float64(time.Microsecond))
	}
	remainder := d.Nanoseconds() % int64(time.Microsecond)
	if remainder == 0 {
