}

func formatTimeStd(d time.Duration) string {
	if d == 0 {
		return "0s"
	}
	nanos := d.Nanoseconds()
	microsFloat := float64(nanos) / 1e6
	return fmt.Sprintf("%gµs", microsFloat)
}

