{"command": "cat > /work/main.go << 'GOEOF'
package main

import (
	"context"
	"encoding/binary"
	"fmt"
	"math"
	"math/rand"
	"net"
	"os"
	"os/signal"
	"strconv"
	"strings"
	"sync"
	"syscall"
	"time"
)

const version = "pingu: v-rev9c2e3df"

var penguinFrames = []string{
	" ...        .     ...   ..    ..     ..............            ",
	" ...     ....          ..  ..      ... .....  .. ..       ",
	" ...    .......      ...         ... . ..... #######      ",
	".....  ........ .###############.....  ... ##########.  .",
	" .... ........#####################.  ... ###########     ",
	"      ....... ######################.... ############     ",
	".    .  .... ########################... ###########      ",
	"   ..   ....#########################.. .###########      ",
	"    .       #########################.   .##########      ",
	"   ....     .########################.      ########      ",
	"  .....      .  ####################.        #######.     ",
	"......     .. . ################## . .      .#######      ",
	"......       #####################  .      .#######       ",
	"......   .###########################  ..  #######        ",
	"...    . ########################################.        ",
	"       ####################################### .          ",
	"      ##################################    .             ",
	"     ###################################  ........        ",
	"  .#####################################    .........     ",
	" .#######################################       .... . .  ",
}

func init() {
	for i := range penguinFrames {
		for len(penguinFrames[i]) < 58 {
			penguinFrames[i] += " "
		}
		penguinFrames[i] = penguinFrames[i][:58]
	}
}

type pingResult struct {
	addr  string
	ttl   int
	rtt   time.Duration
	seq   int
	bytes int
}

func main() {
	if len(os.Args) < 2 {
		fmt.Fprintln(os.Stderr, "[ ERROR ] must requires an argument")
		os.Exit(1)
	}

	count := 20
	privileged := false
	host := ""

	i := 1
	for i < len(os.Args) {
		switch os.Args[i] {
		case "-h", "--help":
			printHelp()
			os.Exit(0)
		case "-V", "--version":
			fmt.Println(version)
			os.Exit(0)
		case "-P", "--privilege":
			privileged = true
			i++
		case "-c":
			i++
			if i >= len(os.Args) {
				fmt.Fprintln(os.Stderr, "[ ERROR ] count value required")
				os.Exit(1)
			}
			n, err := strconv.Atoi(os.Args[i])
			if err != nil {
				fmt.Fprintln(os.Stderr, "[ ERROR ] invalid count value")
				os.Exit(1)
			}
			count = n
			i++
		case "--count":
			i++
			if i >= len(os.Args) {
				fmt.Fprintln(os.Stderr, "[ ERROR ] count value required")
				os.Exit(1)
			}
			n, err := strconv.Atoi(os.Args[i])
			if err != nil {
				fmt.Fprintln(os.Stderr, "[ ERROR ] invalid count value")
				os.Exit(1)
			}
			count = n
			i++
		default:
			if strings.HasPrefix(os.Args[i], "-c=") {
				val := strings.TrimPrefix(os.Args[i], "-c=")
				n, err := strconv.Atoi(val)
				if err != nil {
					fmt.Fprintln(os.Stderr, "[ ERROR ] invalid count value")
					os.Exit(1)
				}
				count = n
				i++
			} else {
				host = os.Args[i]
				i++
			}
		}
	}

	if host == "" {
		fmt.Fprintln(os.Stderr, "[ ERROR ] must requires an argument")
		os.Exit(1)
	}

	runPing(host, count, privileged)
}

func printHelp() {
	fmt.Println("Usage:")
	fmt.Println("  pingu [OPTIONS] HOST")
	fmt.Println()
	fmt.Println("`ping` command but with pingu")
	fmt.Println()
	fmt.Println("Application Options:")
	fmt.Println("  -c, --count=     Stop after <count> replies (default: 20)")
	fmt.Println("  -P, --privilege  Enable privileged mode")
	fmt.Println("  -V, --version    Show version")
	fmt.Println()
	fmt.Println("Help Options:")
	fmt.Println("  -h, --help       Show this help message")
}

func runPing(host string, count int, _ bool) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
	go func() {
		<-sigCh
		cancel()
	}()

	// Resolve to IPv4 address
	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: failed to init pinger lookup %s: %v\n", host, err)
		return
	}
	if len(ips) == 0 {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: failed to resolve %s\n", host)
		return
	}
	targetIP := ips[0].IP

	// Open ICMP socket
	conn, err := net.ListenPacket("ip4:icmp", "0.0.0.0")
	if err != nil {
		fmt.Fprintf(os.Stderr, "[ ERROR ] an error occurred while initializing pinger: %v\n", err)
		return
	}
	defer conn.Close()

	dstAddr := net.IPAddr{IP: targetIP}
	rand.Seed(time.Now().UnixNano())
	myID := uint16(rand.Int())

	// Track sent packets by sequence number
	sentLock := &sync.Mutex{}
	sent := make(map[int]time.Time)

	// Results
	resultLock := &sync.Mutex{}
	results := []*pingResult{}
	received := 0
	frameIdx := 0
	ackReceived := make(chan *pingResult, count)

	// Receiver
	go func() {
		buf := make([]byte, 1500)
		for {
			select {
			case <-ctx.Done():
				return
			default:
			}
			conn.SetReadDeadline(time.Now().Add(3 * time.Second))
			n, addr, err := conn.ReadFrom(buf)
			if err != nil {
				continue
			}
			if n < 8 {
				continue
			}
			// Only process echo replies (type=0)
			if buf[0] != 0 {
				continue
			}
			// ICMP header: type(1) + code(1) + checksum(2) + ID(2) + Seq(2)
			respID := binary.BigEndian.Uint16(buf[4:6])
			respSeq := int(binary.BigEndian.Uint16(buf[6:8]))
			if respID != myID {
				continue
			}
			sentLock.Lock()
			startTime, ok := sent[respSeq]
			delete(sent, respSeq)
			sentLock.Unlock()
			if !ok {
				continue
			}
			rtt := time.Since(startTime)
			pr := &pingResult{
				addr:  addr.String(),
				ttl:   64,
				rtt:   rtt,
				seq:   respSeq,
				bytes: 32,
			}
			resultLock.Lock()
			results = append(results, pr)
			received++
			resultLock.Unlock()
			ackReceived <- pr
		}
	}()

	fmt.Printf("PING %s (%s) type `Ctrl-C` to abort\n", host, targetIP.String())

	// Send all packets
	for seq := 0; seq < count; seq++ {
		data := make([]byte, 64)
		// ICMP Echo Request
		data[0] = 8 // Type: Echo Request
		data[1] = 0 // Code
		binary.BigEndian.PutUint16(data[4:6], myID)     // ID
		binary.BigEndian.PutUint16(data[6:8], uint16(seq)) // Sequence
		binary.BigEndian.PutUint64(data[8:16], uint64(time.Now().UnixNano()))
		// Fill rest with pattern (RFC 792 suggests id*2 + seq)
		for j := 16; j < 64; j++ {
			data[j] = byte(seq + j)
		}

		// Checksum over entire packet
		var sum uint32
		for j := 0; j < len(data)-1; j += 2 {
			sum += uint32(data[j])<<8 | uint32(data[j+1])
		}
		if len(data)%2 == 1 {
			sum += uint32(data[len(data)-1]) << 8
		}
		for sum > 0xFFFF {
			sum = (sum >> 16) + (sum & 0xFFFF)
		}
		binary.BigEndian.PutUint16(data[2:4], uint16(^sum))

		sendTime := time.Now()
		if _, err := conn.WriteTo(data, &dstAddr); err != nil {
			fmt.Fprintf(os.Stderr, "[ ERROR ] send failed: %v\n", err)
			continue
		}
		sentLock.Lock()
		sent[seq] = sendTime
		sentLock.Unlock()
	}

	// Wait for all responses
	for received < count {
		select {
		case <-ctx.Done():
			goto printStats
		case r := <-ackReceived:
			frame := penguinFrames[frameIdx%len(penguinFrames)]
			frameIdx++
			fmt.Printf("%s seq=%d 32bytes from %s: ttl=%d time=%sµs\n",
				frame, r.seq, r.addr, r.ttl, formatTime(r.rtt))
		case <-time.After(15 * time.Second):
			goto printStats
		}
	}

printStats:
	cancel()
	time.Sleep(200 * time.Millisecond)

	// Print statistics
	fmt.Printf("\n───────── %s ping statistics ─────────\n", host)
	lossPct := float64(0)
	if count > 0 {
		lossPct = float64(count-received) / float64(count) * 100
	}
	fmt.Printf("PACKET STATISTICS: %d transmitted => %d received (%.0f%% loss)\n", count, received, lossPct)

	if len(results) > 0 {
		minRtt := results[0].rtt
		maxRtt := results[0].rtt
		totalNanos := int64(0)
		for _, r := range results {
			totalNanos += int64(r.rtt)
			if r.rtt < minRtt {
				minRtt = r.rtt
			}
			if r.rtt > maxRtt {
				maxRtt = r.rtt
			}
		}
		avgRtt := time.Duration(totalNanos / int64(len(results)))

		// stddev
		var sumSqDiff float64
		for _, r := range results {
			diff := float64(r.rtt - avgRtt)
			sumSqDiff += diff * diff
		}
		stddev := time.Duration(math.Sqrt(sumSqDiff / float64(len(results))))

		fmt.Printf("ROUND TRIP: min=%sµs avg=%sµs max=%sµs stddev=%sµs\n",
			formatTime(minRtt), formatTime(avgRtt), formatTime(maxRtt), formatTimeStd(stddev))
	}
}

func formatTime(d time.Duration) string {
	nanos := d.Nanoseconds()
	if nanos%1000 == 0 {
		return strconv.FormatInt(nanos/1000, 10)
	}
	micros := float64(nanos) / 1e6
	s := strconv.FormatFloat(micros, 'f', 3, 64)
	// Trim trailing zeros after decimal point but keep at least one
	return s
}

func formatTimeStd(d time.Duration) string {
	if d == 0 {
		return "0"
	}
	nanos := d.Nanoseconds()
	if nanos%1000 == 0 {
		return strconv.FormatInt(nanos/1000, 10)
	}
	micros := float64(nanos) / 1e6
	s := strconv.FormatFloat(micros, 'f', 3, 64)
	return s
}
GOEOF"}

