	sentLock := &sync.Mutex{}
	sent := make(map[int]time.Time)

	// Store results
	resultLock := &sync.Mutex{}
	results := []*pingResult{}
	received := 0
	frameIdx := 0
	waitCh := make(chan *pingResult, count+1)

	// Receiver goroutine
	go func() {
		buf := make([]byte, 1500)
		for {
			select {
			case <-ctx.Done():
				return
			default:
			}
			conn.SetReadDeadline(time.Now().Add(3 * time.Second))
			n, addr, err := conn.ReadFrom(buf)
			if err != nil {
				continue
			}
			if n < 8 {
				continue
			}
