			startTime, ok := sent[respSeq]
			delete(sent, respSeq)
			sentLock.Unlock()
			if !ok {
				continue
			}
			rtt := time.Since(startTime)
			pr := &pingResult{
				addr:  addr.String(),
				ttl:   int(buf[1]), // code field, should be 0; TTL is from IP header
				rtt:   rtt,
				seq:   respSeq,
				bytes: 32,
			}
			resultLock.Lock()
			results = append(results, pr)
			received++
			resultLock.Unlock()
			waitCh <- pr
		}
	}()

