	for seq := 0; seq < count; seq++ {
		data := make([]byte, 64)
		data[0] = 8                           // ICMP Echo Request
		data[1] = 0                           // Code
		binary.BigEndian.PutUint16(data[4:6], myID)     // ID
		binary.BigEndian.PutUint16(data[6:8], uint16(seq)) // Sequence
		binary.BigEndian.PutUint64(data[8:16], uint64(time.Now().UnixNano()))

