{"command": "# The frames differ because responses come back in different order.
# Let me compare the actual frame content extracted from each by seq number
python3 -c "
import subprocess

def get_frames(binary, args):
    result = subprocess.run([binary] + args, capture_output=True, text=True)
    lines = result.stdout.split(chr(10))
    frames = {}
    for line in lines[1:]:
        if 'seq=' in line:
            idx = line.index('seq=')
            frame = line[:idx]
            seq_start = line.index('seq=') + 4
            # extract seq number until space
            seq_str = ''
            for c in line[seq_start:]:
                if c.isdigit():
                    seq_str += c
                else:
                    break
            if seq_str:
                frames[int(seq_str)] = frame
    return frames

orig_frames = get_frames('/workspace/executable', ['-c', '20', 'localhost'])
mine_frames = get_frames('/work/executable', ['-c', '20', '127.0.0.1'])

for seq in range(20):
    if seq in orig_frames and seq in mine_frames:
        if orig_frames[seq] == mine_frames[seq]:
            print(f'Frame {seq}: MATCH')
        else:
            print(f'Frame {seq}: DIFF')
            print(f'  orig len={len(orig_frames[seq])}: {repr(orig_frames[seq][-10:])}')
            print(f'  mine len={len(mine_frames[seq])}: {repr(mine_frames[seq][-10:])}')
    else:
        print(f'Frame {seq}: MISSING')
" 2>&1"}

